package controller; import javax.swing.*; import util.JapandiTheme; import service.*; import service.impl.*;
public class TextTranslateFrame extends BaseFrame{ TranslationService service=new TranslationServiceImpl(); public TextTranslateFrame(){super("打字翻譯",420,680);JPanel p=root();p.add(header("打字翻譯"));JTextArea input=new JTextArea("請喝水");input.setBounds(50,125,310,120);p.add(input);JComboBox<String> lang=new JComboBox<>(new String[]{"越南文","印尼文","菲律賓文"});lang.setBounds(50,265,310,42);p.add(lang);JButton b=JapandiTheme.primary("翻譯");b.setBounds(50,325,310,42);p.add(b);JTextArea out=new JTextArea();out.setBounds(50,390,310,120);p.add(out);b.addActionListener(e->out.setText(service.translate(input.getText(),lang.getSelectedItem().toString())));p.add(bottomNav());} }